import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { cartAPI } from '../services/api';
import { useAuth } from './AuthContext';

const CartContext = createContext(null);

export function CartProvider({ children }) {
  const { user, isLoggedIn } = useAuth();
  const [cart, setCart]       = useState(null);
  const [loading, setLoading] = useState(false);

  // Fetch cart from backend whenever user logs in
  const fetchCart = useCallback(async () => {
    if (!isLoggedIn() || !user?.id) return;
    setLoading(true);
    try {
      const res = await cartAPI.getCart(user.id);
      setCart(res.data);
    } catch (err) {
      // 404 is expected when cart is empty and auto-created
      setCart(null);
    } finally {
      setLoading(false);
    }
  }, [user, isLoggedIn]);

  useEffect(() => {
    fetchCart();
  }, [fetchCart]);

  // ─── Add item to cart ────────────────────────────────────────────────────────
  const addItem = async (book, quantity = 1) => {
    if (!isLoggedIn() || !user?.id) throw new Error('Login required');
    const payload = {
      bookId:     book.id,
      bookTitle:  book.title,
      bookAuthor: book.author,
      price:      book.price,
      quantity,
    };
    const res = await cartAPI.addItem(user.id, payload);
    setCart(res.data);
    return res.data;
  };

  // ─── Remove a single item ────────────────────────────────────────────────────
  const removeItem = async (itemId) => {
    if (!user?.id) return;
    const res = await cartAPI.removeItem(user.id, itemId);
    setCart(res.data);
    return res.data;
  };

  // ─── Update quantity ─────────────────────────────────────────────────────────
  const updateQuantity = async (itemId, quantity) => {
    if (!user?.id) return;
    const res = await cartAPI.updateQuantity(user.id, itemId, { quantity });
    setCart(res.data);
    return res.data;
  };

  // ─── Clear entire cart ───────────────────────────────────────────────────────
  const clearCart = async () => {
    if (!user?.id) return;
    const res = await cartAPI.clearCart(user.id);
    setCart(res.data);
    return res.data;
  };

  // ─── Derived helpers ─────────────────────────────────────────────────────────
  const totalItems    = cart?.totalItems  ?? 0;
  const totalPrice    = cart?.totalPrice  ?? 0;
  const cartItems     = cart?.items       ?? [];
  const isInCart      = (bookId) => cartItems.some(item => item.bookId === bookId);

  return (
    <CartContext.Provider value={{
      cart, loading, cartItems, totalItems, totalPrice,
      addItem, removeItem, updateQuantity, clearCart, fetchCart, isInCart,
    }}>
      {children}
    </CartContext.Provider>
  );
}

export const useCart = () => useContext(CartContext);
